    float max_val = predictions[0];
    for (int i = 1; i < NUM_CLASSES; i++) {
        if (predictions[i] > max_val) max_val = predictions[i];
    }
    
    float sum = 0.0f;
    for (int i = 0; i < NUM_CLASSES; i++) {
        predictions[i] = expf(predictions[i] - max_val);
        sum += predictions[i];
    }
    
    for (int i = 0; i < NUM_CLASSES; i++) {
        predictions[i] /= sum;
    }
