// Get predicted class
int get_predicted_class(const float* predictions) {
    int best_class = 0;
    float best_prob = predictions[0];
    
    for (int i = 1; i < NUM_CLASSES; i++) {
        if (predictions[i] > best_prob) {
            best_prob = predictions[i];
            best_class = i;
        }
    }
    
    return best_class;
}

// Check if detected bird is a pest
int is_pest_bird(int class_index) {
    if (class_index >= 0 && class_index < NUM_CLASSES) {
        return (BIRD_TYPES[class_index] == PEST_BIRD) ? 1 : 0;
    }
    return 0;
}

// Get bird species name
const char* get_bird_name(int class_index) {
    if (class_index >= 0 && class_index < NUM_CLASSES) {
        return BIRD_SPECIES[class_index];
    }
    return "Unknown";
}

